const fs = require('node:fs');
const path = require('node:path');

const DEFAULT_ENTRY_FILE = path.join('public', 'style.css');
const DEFAULT_OUTPUT_FILE = path.join('public', 'style.bundle.css');

function normalizeImportPath(importUrl) {
    return String(importUrl || '')
        .replace(/^url\((.*)\)$/i, '$1')
        .trim()
        .replace(/^['"]|['"]$/g, '')
        .split('?')[0]
        .replace(/^\/+/, '');
}

function resolveImportFile(rootDir, importPath) {
    const normalizedImportPath = normalizeImportPath(importPath);
    const directPath = path.join(rootDir, normalizedImportPath);

    if (fs.existsSync(directPath)) {
        return { normalizedImportPath, absoluteImportPath: directPath };
    }

    const publicPath = path.join(rootDir, 'public', normalizedImportPath);
    return {
        normalizedImportPath: normalizePathForOutput(path.relative(rootDir, publicPath)),
        absoluteImportPath: publicPath
    };
}

function normalizePathForOutput(inputPath) {
    return String(inputPath || '').replace(/\\/g, '/');
}

function parseCssImports(cssContent) {
    const imports = [];
    const importPattern = /@import\s+(?:url\()?['"]?([^'";)]+)['"]?\)?\s*;/gi;
    let match;

    while ((match = importPattern.exec(cssContent)) !== null) {
        imports.push(normalizeImportPath(match[1]));
    }

    return imports;
}

function getNonImportCss(cssContent) {
    return cssContent
        .replace(/@import\s+(?:url\()?['"]?([^'";)]+)['"]?\)?\s*;/gi, '')
        .trim();
}

function buildCssBundle(rootDir = process.cwd(), options = {}) {
    const entryFile = options.entryFile || DEFAULT_ENTRY_FILE;
    const outputFile = options.outputFile || DEFAULT_OUTPUT_FILE;
    const entryPath = path.join(rootDir, entryFile);
    const outputPath = path.join(rootDir, outputFile);

    if (!fs.existsSync(entryPath)) {
        throw new Error(`CSS entry file not found: ${entryFile}`);
    }

    const entryCss = fs.readFileSync(entryPath, 'utf8');
    const importPaths = parseCssImports(entryCss);

    if (importPaths.length === 0) {
        throw new Error(`No CSS imports found in ${entryFile}`);
    }

    const header = [
        '/**',
        ' * F1 Guesser Duel bundled stylesheet.',
        ' *',
        ' * Generated from public/style.css by scripts/build-css-bundle.js.',
        ' * Do not edit this file manually; edit the files from public/css/ instead.',
        ' */',
        ''
    ].join('\n');

    const sections = [];
    const nonImportCss = getNonImportCss(entryCss);
    if (nonImportCss) {
        sections.push(`/* Source: ${entryFile} */\n${nonImportCss}`);
    }

    for (const relativeImportPath of importPaths) {
        const { normalizedImportPath, absoluteImportPath } = resolveImportFile(rootDir, relativeImportPath);

        if (!fs.existsSync(absoluteImportPath)) {
            throw new Error(`Imported CSS file not found: ${normalizedImportPath}`);
        }

        const importedCss = fs.readFileSync(absoluteImportPath, 'utf8').trimEnd();
        sections.push(`/* Source: ${normalizedImportPath} */\n${importedCss}`);
    }

    const bundleContent = `${header}${sections.join('\n\n')}\n`;
    fs.mkdirSync(path.dirname(outputPath), { recursive: true });
    fs.writeFileSync(outputPath, bundleContent, 'utf8');

    return {
        entryFile,
        outputFile,
        imports: importPaths,
        bytes: Buffer.byteLength(bundleContent, 'utf8')
    };
}

function runCli() {
    const rootDir = process.cwd();
    const result = buildCssBundle(rootDir);
    console.log(`CSS bundle creat: ${result.outputFile}`);
    console.log(`Module CSS incluse: ${result.imports.length}`);
    console.log(`Dimensiune bundle: ${(result.bytes / 1024).toFixed(2)} KB`);
}

if (require.main === module) {
    try {
        runCli();
    } catch (error) {
        console.error(`Eroare build CSS: ${error.message}`);
        process.exitCode = 1;
    }
}

module.exports = {
    buildCssBundle,
    getNonImportCss,
    normalizeImportPath,
    parseCssImports,
    resolveImportFile
};
